using Financeiro.Domain.Entities; using Financeiro.Domain.Interfaces.Repositories; using Financeiro.Infrastructure.Persistence; using Microsoft.EntityFrameworkCore;
namespace Financeiro.Infrastructure.Repositories; public class DespesaPeriodoRepository : IDespesaPeriodoRepository { private readonly AppDbContext _ctx; public DespesaPeriodoRepository(AppDbContext ctx){_ctx=ctx;} public async Task AddAsync(DespesaPeriodo entity,CancellationToken cancellationToken=default)=> await _ctx.DespesasPeriodo.AddAsync(entity,cancellationToken); public Task<DespesaPeriodo?> GetByIdAsync(Guid id,CancellationToken cancellationToken=default)=> _ctx.DespesasPeriodo.FirstOrDefaultAsync(x=>x.Id==id,cancellationToken); public void Remove(DespesaPeriodo entity)=>_ctx.DespesasPeriodo.Remove(entity); }
